{"content":"570: // The controller can also implement controller.Debuggable, in which case the debug handler is registered with the given mux.
571: func BuildControllers(ctx context.Context, controllerCtx ControllerContext, controllerDescriptors map[string]*ControllerDescriptor,
572: 	unsecuredMux *mux.PathRecorderMux, healthzHandler HealthCheckAdder) ([]Controller, error) {
573: 	logger := klog.FromContext(ctx)
574: 	var (
575: 		controllers []Controller
576: 		checks      []healthz.HealthChecker
577: 	)
578: 	buildController := func(controllerDesc *ControllerDescriptor) error {
579: 		controllerName := controllerDesc.Name()
580: 		ctrl, err := controllerDesc.BuildController(ctx, controllerCtx)
581: 		if err != nil {
582: 			logger.Error(err, "Error initializing a controller", "controller", controllerName)
583: 			return err
584: 		}
585: 		if ctrl == nil {
586: 			logger.Info("Warning: skipping controller", "controller", controllerName)
587: 			return nil
588: 		}
589: 
590: 		check := controllerhealthz.NamedPingChecker(controllerName)
591: 		// check if the controller supports and requests a debugHandler,
592: 		// and it needs the unsecuredMux to mount the handler onto.
593: 		if debuggable, ok := ctrl.(controller.Debuggable); ok && unsecuredMux != nil {
594: 			if debugHandler := debuggable.DebuggingHandler(); debugHandler != nil {
595: 				basePath := "/debug/controllers/" + controllerName
596: 				unsecuredMux.UnlistedHandle(basePath, http.StripPrefix(basePath, debugHandler))
597: 				unsecuredMux.UnlistedHandlePrefix(basePath+"/", http.StripPrefix(basePath, debugHandler))
598: 			}
599: 		}
600: 		if healthCheckable, ok := ctrl.(controller.HealthCheckable); ok {
601: 			if realCheck := healthCheckable.HealthChecker(); realCheck != nil {
602: 				check = controllerhealthz.NamedHealthChecker(controllerName, realCheck)
603: 			}
604: 		}
605: 
606: 		controllers = append(controllers, ctrl)
607: 		checks = append(checks, check)
608: 		return nil
609: 	}
610: 
611: 	// Always start the SA token controller first using a full-power client, since it needs to mint tokens for the rest
612: 	// If this fails, just return here and fail since other controllers won't be able to get credentials.
613: 	if serviceAccountTokenControllerDescriptor, ok := controllerDescriptors[names.ServiceAccountTokenController]; ok {
614: 		if err := buildController(serviceAccountTokenControllerDescriptor); err != nil {
615: 			return nil, err
616: 		}
617: 	}
618: 
619: 	// Each controller is passed a context where the logger has the name of
620: 	// the controller set through WithName. That name then becomes the prefix of
621: 	// all log messages emitted by that controller.
622: 	//
623: 	// In StartController, an explicit "controller" key is used instead, for two reasons:
624: 	// - while contextual logging is alpha, klog.LoggerWithName is still a no-op,
625: 	//   so we cannot rely on it yet to add the name
626: 	// - it allows distinguishing between log entries emitted by the controller
627: 	//   and those emitted for it - this is a bit debatable and could be revised.
628: 	for _, controllerDesc := range controllerDescriptors {
629: 		if controllerDesc.RequiresSpecialHandling() {
630: 			continue
631: 		}
632: 
633: 		if !controllerCtx.IsControllerEnabled(controllerDesc) {
634: 			logger.Info("Warning: controller is disabled", "controller", controllerDesc.Name())
635: 			continue
636: 		}
637: 
638: 		if err := buildController(controllerDesc); err != nil {
639: 			return nil, err
640: 		}
641: 	}
642: 
643: 	// Register the checks.
644: 	if len(checks) > 0 {
645: 		healthzHandler.AddHealthChecker(checks...)
646: 	}
647: 	return controllers, nil
648: }
