91: // BuildController creates a controller based on the given descriptor.
92: // The associated controller's constructor is called at the end, so the same contract applies for the return values here.
93: func (r *ControllerDescriptor) BuildController(ctx context.Context, controllerCtx ControllerContext) (Controller, error) {
94: 	logger := klog.FromContext(ctx)
95: 	controllerName := r.Name()
96: 
97: 	for _, featureGate := range r.GetRequiredFeatureGates() {
98: 		if !utilfeature.DefaultFeatureGate.Enabled(featureGate) {
99: 			logger.Info("Controller is disabled by a feature gate",
100: 				"controller", controllerName,
101: 				"requiredFeatureGates", r.GetRequiredFeatureGates())
102: 			return nil, nil
103: 		}
104: 	}
105: 
106: 	if r.IsCloudProviderController() {
107: 		logger.Info("Skipping a cloud provider controller", "controller", controllerName)
108: 		return nil, nil
109: 	}
110: 
111: 	ctx = klog.NewContext(ctx, klog.LoggerWithName(logger, controllerName))
112: 	return r.GetControllerConstructor()(ctx, controllerCtx, controllerName)
113: }
